export interface LogEntry {
  level:    'info' | 'warn' | 'error' | 'debug';
  message:  string;
  data:     Record<string, unknown>;
  errors:   Error[];
  context:  Record<string, unknown>;
  ts?:      number;
}

export interface LogxConfig {
  level?:     'silent' | 'error' | 'warn' | 'info' | 'debug';
  pretty?:    boolean;
  json?:      boolean;
  timestamp?: boolean;
  silent?:    boolean;
}

export interface ChildLogger {
  (msg: string, ...args: unknown[]): void;
  info  (msg: string, ...args: unknown[]): void;
  warn  (msg: string, ...args: unknown[]): void;
  error (msg: string, ...args: unknown[]): void;
  debug (msg: string, ...args: unknown[]): void;
  json  (msg: string, ...args: unknown[]): void;
  child (context: Record<string, unknown>): ChildLogger;
}

export interface Logx {
  (msg: string | { silent: boolean }, ...args: unknown[]): void;

  info  (msg: string, ...args: unknown[]): void;
  warn  (msg: string, ...args: unknown[]): void;
  error (msg: string, ...args: unknown[]): void;
  debug (msg: string, ...args: unknown[]): void;

  /** Force JSON output for this single call */
  json    (msg: string, ...args: unknown[]): void;

  /** Merge config */
  config  (opts: LogxConfig): void;

  /** Create a child logger with bound context */
  child   (context: Record<string, unknown>): ChildLogger;

  /** Add global async context */
  context (ctx: Record<string, unknown>): void;

  /** Add a log-level filter */
  filter  (fn: (level: string, entry: LogEntry) => boolean): void;

  /** Add a custom transport */
  use     (transport: (entry: LogEntry) => void | false): void;

  /** Group logs */
  group   (label: string, fn: () => void): void;

  /** Reset all config (for tests) */
  _reset  (): void;
}

declare const logx: Logx;
export { logx as log };
export default logx;
